from joblib import Parallel, delayedimport mathimport matplotlib.pyplot as pltimport numpy as npfrom scipy.signal import find_peaksfrom tqdm import tqdmfrom astropy.timeseries import LombScargleimport fwhm as c_fwhmimport harmonicplt.rcParams['font.sans-serif'] = ['SimHei']  # 使用黑体plt.rcParams['mathtext.fontset'] = 'stix'  # STIX字体支持数学符号plt.rcParams['font.family'] = 'STIXGeneral'plt.rcParams['axes.unicode_minus'] = Falsedef _ls_simulation(series, flux, M, slope):    """    进行蒙特卡洛模拟以生成光曲线的模拟样本。FAP    参数:    series: 时间序列数据，用于计算最小频率。    flux: 流量数据，用于计算平均值和标准差。    M: 模拟的光曲线数量。    slope: 噪声功率谱的斜率。    返回值:    mcx: 模拟后的光曲线数据。    """    # 计算最小频率，为后续的频率计算提供基础    fre_min = 1.0 / (series[-1] - series[0])    # 获取时间序列的长度，用于后续的数组初始化和平均计算    n = len(series)    # 初始化存储模拟结果的数组    mcx = np.zeros(n)    # 生成两组正态分布的随机数，用于模拟数据的随机部分    random1 = np.random.normal(0, 1, M - 1)    random2 = np.random.normal(0, 1, M - 1)    # 对每个时间点进行模拟    for i in range(n):        # 生成从1到M的频率序列，乘以最小频率        frequencies = np.arange(1, M) * fre_min        # 根据频率和斜率计算振幅        amplitudes = math.sqrt(0.5) * (frequencies ** (- slope / 2.0))        # 计算相位        phases = 2 * np.pi * frequencies * i        # 计算模拟的流量数据        mcx[i] = np.sum(amplitudes * (random1 * np.cos(phases) - random2 * np.sin(phases)), axis=0) / n    # 计算流量数据和模拟数据的平均值    ave_lc, ave = np.nanmean(flux), np.nanmean(mcx)    # 根据流量数据和模拟数据的长度决定是否计算标准差    if len(flux) != 1 or len(mcx) != 1:        std_lc, std = np.nanstd(flux, ddof=1), np.nanstd(mcx, ddof=1)    else:        std_lc, std = 0, 0    # 对模拟数据进行标准化，使其平均值和标准差与流量数据一致    mcx -= ave    mcx /= (std / std_lc)    mcx += ave_lc    return mcxdef lsp_Method(series, flux, flux_err, multiple_freq_max=100, divide_freq_step=10):  # 主方法实现    """    Lomb-Scargle周期图方法用于检测光变曲线中的周期性。    参数:    series: 时间序列，观测时间点。    flux: 流量序列，对应时间点的观测值。    M: 模拟次数，默认为10000。    返回:    frequency: 频率数组。    power: 观测数据的功率谱。    sigma1至sigma4: 分别对应不同置信度的sigma水平。    """    series.sort()    # 初始化Lomb-Scargle周期图对象    lsp = LombScargle(series, flux, dy=flux_err)    # 计算频率范围的最小值    frequency_min = 1 / (series[-1] - series[0])    # 设定频率范围的最大值和步长    frequency_max, delta_frequency = frequency_min * multiple_freq_max, frequency_min / divide_freq_step    # 生成频率数组    frequency = np.arange(frequency_min, frequency_max, delta_frequency)    # 计算观测数据的功率谱    power = lsp.power(frequency)    return frequency, powerdef temp_calculator(series, flux, M, frequency):    temp_lsp = LombScargle(series, _ls_simulation(series, flux, M, 0.28))    power = temp_lsp.power(frequency)    return powerdef calculate_Lsp_FAP(series, flux, frequency, M=10000, n_jobs=10):    # 初始化不同置信度的sigma水平列表    sigma1, sigma2, sigma3, sigma4 = [], [], [], []    # 蒙特卡洛模拟    batch_size = max(1, (M + n_jobs - 1) // M)    result = Parallel(n_jobs=n_jobs, batch_size=batch_size)(        delayed(temp_calculator)(series, flux, M, frequency) for i in tqdm(range(M)))    mc_lsp = np.array(result)  # 自动转换为 (10000, n) 的数组    for i in range(len(frequency)):        sort_mc_lsp = np.sort(mc_lsp[:, i])        sigma1.append(sort_mc_lsp[int(M * 0.6826)])        sigma2.append(sort_mc_lsp[int(M * 0.9544)])        sigma3.append(sort_mc_lsp[int(M * 0.9972)])        sigma4.append(sort_mc_lsp[int(M * 0.9999)])    # 返回频率数组、观测数据的功率谱以及不同置信度的sigma水平    sigmas = [sigma1, sigma2, sigma3, sigma4]    return sigmas, mc_lspdef analysis_LSP_Periods(frequency, power, sigma1_list, sigma2_list, sigma3_list, sigma4_list) -> list:    """    分析LSP周期。    根据给定的频率和功率值，分析并返回LSP周期的概率分布。list[0]代表所分析得到的周期,list[1]代表其对应的置信度    参数:    - frequency: 频率数组。    - power: 功率数组，与频率数组对应。    - sigma1, sigma2, sigma3, sigma4: 功率的阈值，用于确定LSP周期的概率分布。    返回:    - 一个列表，包含LSP周期和相应的概率分布百分比。如果最大LSP周期超过2300，则返回[0, 0]。    """    # 初始化LSP周期列表    lsp_periods = []    # 找到功率最大的索引    max_index = np.argmax(power)    # 获取最大功率对应的频率    max_freq = frequency[max_index]    # 获取最大功率    max_power = power[max_index]    # 计算LSP周期    lsp_period = 1 / max_freq    # 获取不同置信度的sigma水平    sigma1 = sigma1_list[max_index]    sigma2 = sigma2_list[max_index]    sigma3 = sigma3_list[max_index]    sigma4 = sigma4_list[max_index]    # 根据功率的大小，确定LSP周期的置信度    if sigma1 < max_power <= sigma2:        lsp_periods.append(lsp_period)        lsp_periods.append('>68.26%')    elif sigma2 < max_power <= sigma3:        lsp_periods.append(lsp_period)        lsp_periods.append('>95.44%')    elif sigma3 < max_power <= sigma4:        lsp_periods.append(lsp_period)        lsp_periods.append('>99.72%')    elif max_power > sigma4:        lsp_periods.append(lsp_period)        lsp_periods.append('>99.99%')    else:        lsp_periods.append(lsp_period)        lsp_periods.append('<68.26%')    # 返回LSP周期列表    return lsp_periodsdef gen_Lsp_plot(source_name, frequency, power, sigma1, sigma2, sigma3, sigma4, save_path, distance=1, height_rate=0.5):    fig, ax1 = plt.subplots()    fig.set_size_inches(12, 8)    fontsize = 12    ax1.plot(frequency, power, color='k')    # max_index = np.argmax(power)    # max_freq = frequency[max_index]    # max_power = power[max_index]    #    # ax1.axvline(x=max_freq, color='red', linestyle='--', label='Max Value Line')    # ax1.annotate('Period={}'.format(round(1 / max_freq, 3)), xy=(max_freq, max_power), xytext=(0, 3),    #              textcoords='offset points',    #              ha='center', va='bottom', fontsize=fontsize)    # 寻峰判定把所有峰值标记出    height = max(power) * height_rate    peaks_index, _ = find_peaks(power, distance=distance, height=height)    # 伪自动化设置标记字体大小    if len(peaks_index) <= 3:        mark_size = 12    elif len(peaks_index) > 3 & len(peaks_index) < 10:        mark_size = 6    else:        mark_size = 3    for i in range(len(peaks_index)):        mark_freq = frequency[peaks_index[i]]        mark_power = power[peaks_index[i]]        # 标记，画出竖线        ax1.axvline(x=mark_freq, color='red', linestyle='--')        ax1.annotate('Period={}'.format(round(1 / mark_freq, 3)), xy=(mark_freq, mark_power), xytext=(0, 4),                     textcoords='offset points',                     ha='center', va='bottom', fontsize=mark_size)    ax1.plot(frequency, sigma1, label='1σ', c='g')    ax1.plot(frequency, sigma2, label='2σ', c='b')    ax1.plot(frequency, sigma3, label='3σ', c='y')    ax1.plot(frequency, sigma4, label='4σ', c='r')    ax1.set_xlabel('Frequency', fontsize=fontsize)    ax1.set_ylabel('LSP', fontsize=fontsize)    ax1.set_xscale('log')    ax1.invert_xaxis()    xticks = np.array([0.1, 0.01, 0.001])    ax2 = ax1.secondary_xaxis('top')    ax2.set_xlabel('Periods', fontsize=fontsize)    ax2.set_xticks(xticks)  # 设置刻度位置    ax2.set_xticklabels(['10', '100', '1000'])    ax1.set_title(f'{source_name} - LSP', fontsize=14)    ax1.legend(loc='best', fontsize=fontsize)    ax1.tick_params(axis='both', direction='in', labelsize=fontsize)    ax1.grid(linestyle='--', alpha=0.5)    plt.savefig(f'{save_path}\\{source_name} - LSP.png', dpi=300)    plt.close()    print(f"{source_name} - LSP绘图完成,保存在{save_path}\\{source_name} - LSP.png")def get_LSP_results(freq, power, self_harmonic=True, peak_width_factor=0.1, n_harmonics=2,                    snr_threshold=3.0, height=0.1, min_prominence_rate=0.5, sigma_threshold=2.0,reverse=True):    """    LSP SNR计算函数，包含突出度检测    参数:    min_prominence: 峰值的最小突出度（相对于最大功率的比例）    """    # 计算最小突出度阈值（基于最大功率）    abs_min_prominence = min_prominence_rate * np.max(power)    # 使用find_peaks并指定突出度阈值    peaks, properties = find_peaks(power,                                   height=max(height, 0.01),                                   prominence=abs_min_prominence,                                   wlen=len(power) // 10)  # 使用信号长度10%的窗口    peak_freqs = freq[peaks]    peak_powers = properties['peak_heights']    prominences = properties['prominences']  # 提取突出度值    snr, fhwm, candidate_periods, candidate_periods_err, frequency_index = [], [], [], [], []    for peak_freq, peak_power, index in zip(peak_freqs, peak_powers, peaks):        # 创建排除掩码（与原始函数相同）        exclude_mask = np.zeros_like(freq, dtype=bool)        exclude_width = peak_width_factor * peak_freq        exclude_mask |= (np.abs(freq - peak_freq) < exclude_width)        # 排除谐波区域（与原始函数相同）        for n in range(2, n_harmonics + 1):            harmonic_freq = n * peak_freq            if harmonic_freq < max(freq):                exclude_mask |= (np.abs(freq - harmonic_freq) < exclude_width)        # 计算局部背景噪声        background_power = np.median(power[~exclude_mask])        snr_value = peak_power / background_power if background_power > 0 else np.inf        if snr_value >= snr_threshold:            # 添加 SNR 到结果列表中            snr.append(snr_value)            # 计算FWHM 从而估算不确定性            fwhm_value = c_fwhm.calculate_fwhm(freq, power, peak_power)["fwhm"]            fhwm.append(fwhm_value)            # u_f = fwhm_value / (2.355 * snr_value)            u_f = fwhm_value / 2            T = 1 / peak_freq            candidate_periods.append(T)            # 周期不确定度误差传递公式 u_T = (1 / f)^2 * u_f            err = (T ** 2) * u_f            candidate_periods_err.append(err)            frequency_index.append(index)        else:            print(f"- 忽略周期{round(1 / peak_freq, 3)}，因为SNR小于{snr_threshold}, snr={snr_value}")    if self_harmonic:        # 自谐波检测        base_mask = harmonic.self_harmonic_detection(candidate_periods, candidate_periods_err,                                                     sigma_threshold=sigma_threshold,reverse=reverse)        snr = [value for value, mask in zip(snr, base_mask) if mask]        candidate_periods = [p for p, mask in zip(candidate_periods, base_mask) if mask]        candidate_periods_err = [p for p, mask in zip(candidate_periods_err, base_mask) if mask]        fhwm = [value for value, mask in zip(fhwm, base_mask) if mask]        prominences = [value for value, mask in zip(prominences, base_mask) if mask]        peak_powers = [value for value, mask in zip(peak_powers, base_mask) if mask]        frequency_index = [value for value, mask in zip(frequency_index, base_mask) if mask]    return candidate_periods, candidate_periods_err, snr, fhwm, peak_powers, prominences, frequency_indexdef plot_LSP(source_name, frequency, power, candidate_periods, candidate_periods_err, snr, series, flux, *args,             plot_mode="save", save_path="."):    plt.figure(figsize=(12, 10))    # 子图1: LSP周期图    plt.subplot(3, 1, 1)    plt.plot(1.0 / frequency, power, 'k-', label='LSP Power')    plt.xscale('log')    plt.xlabel('Period (days)')    plt.ylabel('Power')    plt.title(f'{source_name} Lomb-Scargle Periodogram')    plt.grid(True, linestyle='--', alpha=0.7)    COLORS = ['g', 'b', 'y', 'r', 'c', 'm']    if args:        for i, sigma in enumerate(args[0]):            plt.plot(1.0 / frequency, sigma, label=f'{i + 1}σ', c=COLORS[i])    # 标记检测到的周期    for i, period in enumerate(candidate_periods):        plt.axvline(x=period, color=COLORS[i], linestyle='--',                    label=f'Period: {period:.2f}±{candidate_periods_err[i]:.2f} days\nSNR: {snr[i]:.2f}')    plt.legend()    # 子图2: 原始信号    plt.subplot(3, 1, 2)    plt.plot(series, flux, 'y-', linewidth=0.5, alpha=0.5, label='Signal')    plt.ylabel('Flux')    plt.legend()    plt.grid(True, linestyle='--', alpha=0.7)    model_signals = []    total_fit = np.zeros_like(flux)    for i, period in enumerate(candidate_periods):        print(period)        freq = 1.0 / period        # 使用LombScargle模型拟合单个频率        model = LombScargle(series, flux)        # 重建该频率的正弦波        wave = model.model(series, freq)        model_signals.append(wave)        total_fit += wave  # 叠加到总拟合信号        # 绘制单个周期成分（可选）        plt.subplot(3, 1, 3)        plt.plot(series, wave, color=COLORS[i], linestyle=':', alpha=0.8,                 label=f'Period {period:.2f}d')        plt.legend()    # 绘制总拟合信号    plt.subplot(3, 1, 2)    plt.plot(series, total_fit, 'g--', lw=2, label='Combined Fit')    plt.xlabel('Time (days)')    plt.legend()    plt.subplot(3, 1, 3)    plt.plot(series, total_fit, 'b', lw=2, label='Combined Fit')    plt.legend()    plt.xlabel('Time (days)')    plt.ylabel('Flux')    plt.grid(True, linestyle='--', alpha=0.7)    plt.tight_layout()    if plot_mode == "show":        plt.show()    if plot_mode == "save":        plt.savefig(f'{save_path}\\{source_name}_LSP.png', dpi=300)        plt.close()        print(f"{source_name} - LSP绘图完成,保存在{save_path}\\{source_name} - LSP.png")if __name__ == '__main__':    # 测试代码    # 1. 生成测试数据    np.random.seed(42)    t = np.linspace(0, 100, 1000)  # 1000个时间点，范围0-100天    # 创建两个主要周期信号    period1 = 5.0  # 5天周期    period2 = 12.0  # 12天周期    period3 = 9.0    signal = (1.0 * np.sin(2 * np.pi * t / period1) +              0.7 * np.sin(2 * np.pi * t / period2) +              0.8 * np.sin(2 * np.pi * t / (period3)))    # 添加谐波信号    signal += 0.3 * np.sin(2 * np.pi * t / (period1 * 2))  # 一次谐波    signal += 0.1 * np.sin(2 * np.pi * t / (period1 * 3))  # 二次谐波    # 添加噪声    noise = np.random.normal(0, 1, len(t))    signal += noise    # 2. 计算Lomb-Scargle周期图    from astropy.timeseries import LombScargle    frequency_min = 1 / 100  # 最小频率 (0.01 c/d)    frequency_max = 1.0  # 最大频率 (1 c/d)    freq = np.linspace(frequency_min, frequency_max, 10000)    power = LombScargle(t, signal).power(freq)    # 3. 使用get_LSP_results函数分析结果    results = get_LSP_results(freq, power,                              peak_width_factor=0.01,                              height_rate=0.15,                              min_prominence_rate=0.1, self_harmonic=True, n_harmonics=2, snr_threshold=5.0,                              sigma_threshold=0.05)    # 大周期误差太大容易误判为谐波    candidate_periods, candidate_periods_err, snr, fhwm, peak_powers, prominences, frequency_index = results    plot_LSP('Test Source', freq, power, candidate_periods, candidate_periods_err, snr, t, signal)    # 4. 绘制结果    plt.figure(figsize=(12, 8))    # 绘制LSP周期图    plt.subplot(2, 1, 1)    plt.plot(1 / freq, power, 'k-', label='LSP Power')    plt.xscale('log')    plt.xlabel('Period (days)')    plt.ylabel('Power')    plt.title('Lomb-Scargle Periodogram')    plt.grid(True, linestyle='--', alpha=0.7)    # 标记检测到的周期    colors = plt.cm.viridis(np.linspace(0, 1, len(candidate_periods)))    for i, period in enumerate(candidate_periods):        plt.axvline(x=period, color=colors[i], linestyle='--',                    label=f'Period: {period:.2f}±{candidate_periods_err[i]:.2f} days\nSNR: {snr[i]:.2f}')    plt.legend()    # 绘制原始信号    plt.subplot(2, 1, 2)    plt.plot(t, signal, 'b-', alpha=0.7, label='Signal with Noise')    plt.plot(t, signal - noise, 'r-', label='True Signal')    plt.xlabel('Time (days)')    plt.ylabel('Flux')    plt.title('Original Light Curve')    plt.legend()    plt.grid(True, linestyle='--', alpha=0.7)    plt.show()    # 打印检测结果    print("\nLomb-Scargle检测到的周期结果:")    print(f"{'Period (days)':<15} {'Error':<10} {'SNR':<10} {'FWHM':<10} {'Power':<10} {'Prominence':<10}")    for i in range(len(candidate_periods)):        print(f"{candidate_periods[i]:<15.4f} {candidate_periods_err[i]:<10.4f} {snr[i]:<10.2f} "              f"{fhwm[i]:<10.4f} {peak_powers[i]:<10.4f} {prominences[i]:<10.4f}")# 大周期误差太大容易误判为谐波